from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Start with the main subject
    main_subject = list(subject_map.keys())[0] if subject_map else ""
    sentence = main_subject

    # Track relationships for complex sentence construction
    runway_info = []
    elevation_info = []
    location_info = []
    country_info = []
    other_info = []
    classification_info = []

    # Process each triple to create natural language
    for subject, triples in subject_map.items():
        for predicate, obj in triples:
            if predicate == "cityServed":
                other_info.append(f"serves the city of {obj}")
            elif predicate == "mayor":
                other_info.append(f"has a mayor named {obj}")
            elif predicate == "isPartOf":
                location_info.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                other_info.append(f"is operated by {obj}")
            elif predicate == "location":
                location_info.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                elevation_info.append(f"has an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                other_info.append(f"has a runway length of {obj} metres")
            elif predicate == "country":
                country_info.append(f"is located in {obj}")
            elif predicate == "capital":
                other_info.append(f"has {obj} as its capital")
            elif predicate == "language":
                other_info.append(f"where {obj} is spoken")
            elif predicate == "leader":
                other_info.append(f"has {obj} as its leader")
            elif predicate == "owner":
                other_info.append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                runway_info.append(f"The first runway at {subject} is {obj} feet long")
            elif predicate == "1stRunwaySurfaceType":
                runway_info.append(f"The first runway at {subject} is made of {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                runway_info.append(f"The third runway at {subject} is {obj} feet long")
            elif predicate == "icaoLocationIdentifier":
                other_info.append(f"has an ICAO identifier of {obj}")
            elif predicate == "locationIdentifier":
                other_info.append(f"has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                elevation_info.append(f"has an elevation of {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                other_info.append(f"has an IATA identifier of {obj}")
            elif predicate == "nativeName":
                other_info.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                other_info.append(f"has a leader party of {obj}")
            elif predicate == "runwayName":
                other_info.append(f"has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                other_info.append(f"has a runway surface type of {obj}")
            elif predicate == "division":
                classification_info.append(f"{obj} is the division of {subject}")
            elif predicate == "class":
                classification_info.append(f"{obj} is the class of {subject}")
            elif predicate == "order":
                classification_info.append(f"{obj} is the order of {subject}")
            elif predicate == "officialLanguage":
                other_info.append(f"{obj} is the official language of {subject}")
            else:
                # Handle other predicates with more natural phrasing
                normalized_pred = predicate.replace('1stRunway', 'first runway').replace('2ndRunway', 'second runway').replace('3rdRunway', 'third runway').replace('4thRunway', 'fourth runway').replace('5thRunway', 'fifth runway').replace('Length', ' length').replace('SurfaceType', ' surface type').replace('AboveTheSeaLevel', ' above sea level').replace('LocationIdentifier', ' identifier').replace('Iata', 'IATA').replace('Icao', 'ICAO').replace('InFeet', ' in feet').replace('InMetres', ' in metres')
                if "runway" in predicate or "elevation" in predicate or "length" in predicate:
                    other_info.append(f"has a {normalized_pred} of {obj}")
                else:
                    other_info.append(f"is {obj}" if predicate in ["leader", "owner", "mayor", "capital"] else f"has a {normalized_pred} of {obj}")

    # Build complex sentence structure
    if runway_info:
        sentence += " " + " ".join(runway_info)
    if elevation_info:
        sentence += " " + " ".join(elevation_info)
    if location_info:
        sentence += " " + ", ".join(location_info)
    if country_info:
        sentence += " " + ", ".join(country_info)
    if classification_info:
        sentence += " " + " ".join(classification_info)
    if other_info:
        if sentence and not sentence.endswith(" "):
            sentence += " and "
        sentence += " ".join(other_info)

    return sentence + "."

